// shellCommand renders binary + argv as a copy-pasteable shell line.
// Args containing whitespace or shell metachars are single-quoted;
// existing single quotes get the close-quote/escape/open-quote dance
// so paste-into-bash always works.
func shellCommand(binary string, argv []string) string {
	parts := make([]string, 0, len(argv)+1)
	parts = append(parts, shellQuote(binary))
	for _, a := range argv {
		parts = append(parts, shellQuote(a))
	}
	return strings.Join(parts, " ")
}

func shellQuote(s string) string {
	if s == "" {
		return "''"
	}
	safe := true
	for _, r := range s {
		switch {
		case r >= 'a' && r <= 'z':
		case r >= 'A' && r <= 'Z':
		case r >= '0' && r <= '9':
		case r == '_' || r == '-' || r == '.' || r == '/' || r == ':' || r == ',' || r == '=' || r == '@' || r == '+' || r == '%':
		default:
			safe = false
		}
		if !safe {
			break
		}
	}
	if safe {
		return s
	}
	return "'" + strings.ReplaceAll(s, "'", `'\''`) + "'"
}

// filenameOf trims everything before the last path separator. Used
// inline by the spawn list to build the detail link without exposing
// host paths.
func filenameOf(p string) string {
	if i := strings.LastIndexAny(p, "/\\"); i >= 0 {
		return p[i+1:]
	}
	return p
}

// binaryPlaceholder returns what the Edit form's binary path input
// should hint when the registry has no override: the auto-detected
// path (registry/PATH/scan hit) so the user can see what wick would
// run, falling back to the bare type name when nothing was found.
func binaryPlaceholder(st provider.Status) string {
	if st.Instance.Binary != "" {
		return string(st.Instance.Type)
	}
	if st.Path != "" {
		return st.Path
	}
	return string(st.Instance.Type)
}

